class TokenBudget:
    def __init__(self, max_tokens: int):
        self.max_tokens = max_tokens
        self.consumed = 0

    def consume(self, usage) -> None:
        self.consumed += usage.input_tokens + usage.output_tokens
        if self.consumed > self.max_tokens:
            raise RuntimeError(f"Token budget exceeded: {self.consumed} > {self.max_tokens}")

    def remaining(self) -> int:
        return max(0, self.max_tokens - self.consumed)
